// Parse the campaign data and prepare individual emails
const campaign = $input.first().json.body || $input.first().json;

const templateId = campaign.templateId;
const employees = campaign.employees || [];
const campaignId = campaign.id;
const client = campaign.client || 'Company';
const senderName = campaign.senderName || 'Security Alert';
const senderEmail = campaign.senderEmail || 'alert@security-notice.com';
const landing = campaign.landing || 'microsoft';
const schedule = campaign.schedule || 'now';

// Base URLs for tracking
const baseUrl = 'http://soc.palisadeone.com:5678/webhook';
const trainingUrl = 'https://palisadeone.com/phish-training.html';

// Map landing page types to their webhook paths
const landingPaths = {
  'microsoft': '/phish-landing-microsoft',
  'google': '/phish-landing-google',
  'generic': '/phish-landing-generic',
  'none': '/phish-click-only'
};

const output = employees.map((emp, index) => {
  // Build unique tracking URL
  const clickUrl = `${baseUrl}${landingPaths[landing] || landingPaths['none']}?uid=${emp.uid}&cid=${campaignId}`;
  const openTrackUrl = `${baseUrl}/phish-open?uid=${emp.uid}&cid=${campaignId}`;

  // Calculate send delay based on schedule
  let delayMs = 0;
  if (schedule === 'stagger-5') delayMs = index * 5 * 60 * 1000;
  else if (schedule === 'stagger-15') delayMs = index * 15 * 60 * 1000;
  else if (schedule === 'stagger-60') delayMs = index * 60 * 60 * 1000;
  else if (schedule === 'random-24h') delayMs = Math.floor(Math.random() * 24 * 60 * 60 * 1000);

  return {
    json: {
      to: emp.email,
      name: emp.name || emp.email.split('@')[0],
      uid: emp.uid,
      campaignId,
      client,
      senderName,
      senderEmail,
      templateId,
      clickUrl,
      openTrackUrl,
      trainingUrl: `${trainingUrl}?uid=${emp.uid}&cid=${campaignId}`,
      landing,
      delayMs,
      subject: campaign.subject || ''
    }
  };
});

return output;

// Build the actual email HTML from the template
const item = $input.first().json;

// Template library (simplified versions — full HTML in dashboard.html)
const templates = {
  'm365-password': {
    subject: 'Your password expires in 24 hours',
    body: `<div style="font-family:Segoe UI,sans-serif;max-width:600px;margin:0 auto">
<div style="background:#0078d4;padding:16px 24px;color:white;font-size:18px;font-weight:600">Microsoft 365</div>
<div style="padding:24px;border:1px solid #ddd;border-top:none">
<p>Your Microsoft 365 password will expire in <strong>24 hours</strong>.</p>
<p>To avoid losing access to your email and files, please update your password immediately.</p>
<p style="text-align:center;margin:28px 0"><a href="${item.clickUrl}" style="background:#0078d4;color:white;padding:12px 32px;text-decoration:none;border-radius:4px;font-weight:600">Update Password Now</a></p>
<p style="color:#666;font-size:13px">If you did not request this change, please disregard this email.</p>
<p style="color:#999;font-size:12px">Microsoft 365 Security Team</p>
</div></div>`
  },
  'salary-adjustment': {
    subject: 'Salary Adjustment Notice — Confidential',
    body: `<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;padding:20px">
<p>Dear ${item.name},</p>
<p>Following the annual compensation review, your salary has been adjusted effective next pay period.</p>
<p>To view your updated compensation details, please log in to the HR portal:</p>
<p style="text-align:center;margin:24px 0"><a href="${item.clickUrl}" style="background:#2e7d32;color:white;padding:12px 32px;text-decoration:none;border-radius:4px;font-weight:600">View Compensation Update</a></p>
<p style="color:#999;font-size:13px"><em>This information is confidential.</em></p>
<p>Human Resources<br>${item.client}</p></div>`
  }
};

// Use template if available, otherwise build a generic one
const tpl = templates[item.templateId];
const subject = item.subject || (tpl ? tpl.subject : 'Action Required');
let body = tpl ? tpl.body : `<p>Please click <a href="${item.clickUrl}">here</a> to take action.</p>`;

// Add invisible tracking pixel for open detection
body += `<img src="${item.openTrackUrl}" width="1" height="1" style="display:none" />`;

return [{
  json: {
    ...item,
    subject,
    htmlBody: body
  }
}];
